#!/usr/bin/env python3
"""make-columnar-embed.py — write an HCEM (HELIX Columnar Embed Matrix) file
from a HuggingFace model's `embed_tokens.weight` tensor.

Wire format (matches `src/columnar_embed_backend.rs`):

    off=0   u32 LE  magic = b"HCEM"
    off=4   u32 LE  version = 1
    off=8   u32 LE  vocab_size
    off=12  u32 LE  hidden_dim
    off=16  u32 LE  dtype_code   (0=fp32, 1=bf16; default bf16 = 1)
    off=20  u8[12]  reserved (zeroed)
    off=32  payload  vocab_size × hidden_dim × bytes_per_dtype, row-major

Row `i` lives at byte offset `32 + i * hidden_dim * bytes_per_dtype`. For
Qwen2.5-0.5B bf16 this is `32 + i * 1792`.

Usage:
    python3 make-columnar-embed.py \\
        --model Qwen/Qwen2.5-0.5B-Instruct \\
        --dtype bf16 \\
        --out rknots/qwen-embed.hcem

Why this exists: HELIX columnar embed avoids shipping the full embedding
matrix at cold start. The proposal + amortization numbers are in
`HELIX_COLUMNAR_EMBED_PROPOSAL.md` / `COLUMNAR_BANDWIDTH_REPORT.md`.
"""

import argparse
import struct
import sys
from pathlib import Path

DEFAULT_MODEL = "Qwen/Qwen2.5-0.5B-Instruct"

HCEM_MAGIC = b"HCEM"
HCEM_VERSION = 1
HCEM_HEADER_BYTES = 32
DTYPE_FP32 = 0
DTYPE_BF16 = 1


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--model", default=DEFAULT_MODEL, help=f"HF model id (default {DEFAULT_MODEL}).")
    parser.add_argument(
        "--dtype",
        choices=("fp32", "bf16"),
        default="bf16",
        help="Output dtype for the row store (default bf16).",
    )
    parser.add_argument(
        "--out",
        required=True,
        help="Output HCEM file path (e.g. rknots/qwen-embed.hcem).",
    )
    args = parser.parse_args()

    try:
        import torch
        torch.set_num_threads(1)
        from safetensors import safe_open
        from huggingface_hub import snapshot_download
    except Exception as e:
        print(f"ERROR: torch/safetensors/huggingface_hub missing: {e}", file=sys.stderr)
        return 2

    print(f"[make-columnar-embed] locating safetensors for {args.model}", file=sys.stderr)
    local_dir = snapshot_download(
        repo_id=args.model,
        allow_patterns=["*.safetensors", "*.json"],
    )
    st_files = sorted(Path(local_dir).glob("*.safetensors"))
    if not st_files:
        print(f"ERROR: no safetensors files found in {local_dir}", file=sys.stderr)
        return 3

    embed_t = None
    EMBED_KEYS = (
        "model.embed_tokens.weight",
        "embed_tokens.weight",
        "transformer.wte.weight",
        # VLM wrappers (Gemma4: model.language_model.*, LLaVA, etc.)
        "model.language_model.embed_tokens.weight",
        "language_model.model.embed_tokens.weight",
        "text_model.model.embed_tokens.weight",
        "language_model.embed_tokens.weight",
    )
    for shard in st_files:
        with safe_open(str(shard), framework="pt", device="cpu") as f:
            for key in f.keys():
                if key in EMBED_KEYS:
                    embed_t = f.get_tensor(key)
                    print(
                        f"[make-columnar-embed] found embed in {shard.name}: {key}",
                        file=sys.stderr,
                    )
                    break
        if embed_t is not None:
            break
    if embed_t is None:
        print("ERROR: no embed_tokens.weight key found across shards", file=sys.stderr)
        return 4

    vocab_size, hidden_dim = int(embed_t.shape[0]), int(embed_t.shape[1])
    print(
        f"[make-columnar-embed] embed shape={tuple(embed_t.shape)} src_dtype={embed_t.dtype}",
        file=sys.stderr,
    )

    if args.dtype == "fp32":
        dtype_code = DTYPE_FP32
        bpe = 4
        row_buf = embed_t.to(torch.float32).contiguous().view(torch.uint8).numpy()
    else:  # bf16
        dtype_code = DTYPE_BF16
        bpe = 2
        # torch.bfloat16 has no numpy mapping; reinterpret as uint16 then uint8.
        row_buf = (
            embed_t.to(torch.bfloat16)
            .contiguous()
            .view(torch.uint16)
            .view(torch.uint8)
            .numpy()
        )

    expected_payload = vocab_size * hidden_dim * bpe
    if row_buf.nbytes != expected_payload:
        print(
            f"ERROR: row buffer {row_buf.nbytes} != expected {expected_payload}",
            file=sys.stderr,
        )
        return 5

    out_path = Path(args.out)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    print(
        f"[make-columnar-embed] writing HCEM: vocab={vocab_size} hidden={hidden_dim} "
        f"dtype={args.dtype} row_bytes={hidden_dim * bpe} payload={expected_payload}",
        file=sys.stderr,
    )

    # Pack header. struct: <4sIIIIB plus 11 bytes reserved = 12 bytes after the
    # dtype_code byte to reach exactly 32 bytes total.
    header = bytearray(HCEM_HEADER_BYTES)
    header[0:4] = HCEM_MAGIC
    struct.pack_into("<I", header, 4, HCEM_VERSION)
    struct.pack_into("<I", header, 8, vocab_size)
    struct.pack_into("<I", header, 12, hidden_dim)
    struct.pack_into("<I", header, 16, dtype_code)  # writes dtype_code in low byte; high 3 bytes reserved
    # bytes 20..32 stay zero (reserved)

    with open(out_path, "wb") as f:
        f.write(bytes(header))
        f.write(row_buf.tobytes())

    final_size = out_path.stat().st_size
    print(
        f"[make-columnar-embed] wrote {out_path} size={final_size} B "
        f"({final_size / (1024 * 1024):.1f} MiB)",
        file=sys.stderr,
    )

    # Sanity: re-parse header.
    with open(out_path, "rb") as f:
        hdr = f.read(HCEM_HEADER_BYTES)
    assert hdr[0:4] == HCEM_MAGIC, "magic roundtrip"
    assert struct.unpack_from("<I", hdr, 4)[0] == HCEM_VERSION
    assert struct.unpack_from("<I", hdr, 8)[0] == vocab_size
    assert struct.unpack_from("<I", hdr, 12)[0] == hidden_dim
    assert hdr[16] == dtype_code
    print(
        f"[make-columnar-embed] header roundtrip OK\n"
        f"  total bytes: {final_size}\n"
        f"  ratio vs dense: {final_size / expected_payload:.6f} (= 1 + header overhead)",
        file=sys.stderr,
    )

    return 0


if __name__ == "__main__":
    sys.exit(main())
